1	import { config, validateConfig } from './config';
2	import { connectDB } from './config/db';
3	import { logger } from './utils/logger';
4	import { loadSensitiveWords } from './middleware/contentFilter';
5	import { startScheduler } from './jobs/scheduler';
6	import app from './app';
7	import fs from 'fs';
8	import path from 'path';
9	
10	async function startServer(): Promise<void> {
11	  try {
12	    // Validate configuration
13	    validateConfig();
14	    logger.info('Configuration validated');
15	
16	    // Ensure upload directories exist
17	    const uploadDirs = [
18	      'portfolios', 'verification-docs', 'settlement-attachments',
19	      'report-evidence', 'deliverables', 'exports'
20	    ];
21	    for (const dir of uploadDirs) {
22	      const dirPath = path.join(config.uploadDir, dir);
23	      if (!fs.existsSync(dirPath)) {
24	        fs.mkdirSync(dirPath, { recursive: true });
25	      }
26	    }
27	    logger.info('Upload directories verified');
28	
29	    // Connect to MongoDB
30	    await connectDB();
31	
32	    // Load sensitive words
33	    try {
34	      await loadSensitiveWords();
35	      logger.info('Sensitive words loaded');
36	    } catch (err) {
37	      logger.warn('Failed to load sensitive words, continuing without filter');
38	    }
39	
40	    // Start background job scheduler
41	    startScheduler();
42	    logger.info('Background job scheduler started');
43	
44	    // Start HTTP server
45	    app.listen(config.port, '0.0.0.0', () => {
46	      logger.info(`Server running on port ${config.port}`);
47	    });
48	  } catch (err) {
49	    logger.error('Failed to start server', { error: err });
50	    process.exit(1);
51	  }
52	}
53	
54	startServer();
