20	export async function getByJob(jobId: string, requesterId: string) {
21	  const job = await Job.findById(jobId);
22	  if (!job) throw new NotFoundError('Job not found');
23	
24	  const requester = await User.findById(requesterId);
25	  if (requester?.role !== 'admin') {
26	    const isParticipant =
27	      job.clientId.toString() === requesterId ||
28	      (job.photographerId && job.photographerId.toString() === requesterId);
29	    if (!isParticipant) {
30	      throw new ForbiddenError('Only job participants can view deliverables');
31	    }
32	  }
33	
34	  return Deliverable.find({ jobId }).sort({ createdAt: -1 });
