1	import fs from 'fs';
2	import path from 'path';
3	import { v4 as uuidv4 } from 'uuid';
4	import { FileAttachment } from '../models';
5	import { config } from '../config';
6	import { ValidationError, NotFoundError } from '../utils/errors';
7	import { validateFileType, validateFileSize, validateFileFormat, sanitizeFilename } from '../utils/documentValidators';
8	import { computeSHA256 } from '../utils/fileChecksum';
9	
10	export interface SaveFileInput {
11	  buffer: Buffer;
12	  originalName: string;
13	  mimeType: string;
14	  parentType: string;
15	  parentId: string;
16	  uploadedBy: string;
17	}
18	
19	/**
20	 * Save a file to the upload directory with a UUID-based filename.
21	 */
22	export async function saveFile(input: SaveFileInput): Promise<{
23	  storagePath: string;
24	  checksum: string;
25	  sizeBytes: number;
26	}> {
27	  const ext = path.extname(input.originalName) || '';
28	  const filename = `${uuidv4()}${ext}`;
29	  const uploadDir = path.resolve(config.uploadDir);
30	
31	  // Ensure upload directory exists
32	  if (!fs.existsSync(uploadDir)) {
33	    fs.mkdirSync(uploadDir, { recursive: true });
34	  }
35	
36	  const storagePath = path.join(uploadDir, filename);
37	  const checksum = computeSHA256(input.buffer);
38	
39	  fs.writeFileSync(storagePath, input.buffer);
40	
41	  return {
42	    storagePath,
43	    checksum,
44	    sizeBytes: input.buffer.length,
45	  };
46	}
47	
48	/**
49	 * Validate file and store it with a FileAttachment record.
50	 */
51	export async function validateAndStore(input: SaveFileInput) {
52	  // Validate file
53	  validateFileType(input.mimeType);
54	  validateFileSize(input.buffer.length);
55	  validateFileFormat(input.buffer, input.mimeType);
56	
57	  const sanitized = sanitizeFilename(input.originalName);
58	
59	  // Save to disk
60	  const { storagePath, checksum, sizeBytes } = await saveFile({
61	    ...input,
62	    originalName: sanitized,
63	  });
64	
65	  // Create FileAttachment record
66	  const attachment = await FileAttachment.create({
67	    parentType: input.parentType,
68	    parentId: input.parentId,
69	    originalName: sanitized,
70	    storagePath,
71	    mimeType: input.mimeType,
72	    sizeBytes,
73	    checksum,
74	    uploadedBy: input.uploadedBy,
75	  });
76	
77	  return attachment;
78	}
79	
80	/**
81	 * Retrieve a file by its FileAttachment ID.
82	 * Enforces strict access control: only the uploader, job participants, or admins
83	 * may access the file. Denied attempts are audit-logged.
84	 */
85	export async function getFile(fileId: string, requesterId: string) {
86	  const { checkDocumentAccess } = await import('./documentAccess.service');
87	  const { User } = await import('../models');
88	
89	  // Look up the requester's role from the DB — never trust caller-supplied role
90	  const requester = await User.findById(requesterId);
91	  const requesterRole = requester?.role || 'alumni';
92	
93	  // checkDocumentAccess throws ForbiddenError if denied and audit-logs the denial
94	  const { file: attachment } = await checkDocumentAccess(
95	    fileId,
96	    requesterId,
97	    requesterRole as any,
98	  );
99	
100	  const filePath = attachment.storagePath;
101	  // Prevent path traversal: resolve and verify the path is inside the upload directory
102	  const resolvedPath = path.resolve(filePath);
103	  const uploadRoot = path.resolve(config.uploadDir);
104	  if (!resolvedPath.startsWith(uploadRoot)) {
105	    throw new ValidationError('Invalid file path');
106	  }
107	
108	  if (!fs.existsSync(resolvedPath)) {
109	    throw new NotFoundError('File not found on disk');
110	  }
111	
112	  const buffer = fs.readFileSync(resolvedPath);
113	
114	  return {
115	    buffer,
116	    mimeType: attachment.mimeType,
117	    filename: attachment.originalName,
118	  };
119	}
