65	export async function getAllProfiles(filters: {
66	  page?: number;
67	  limit?: number;
68	  search?: string;
69	  role?: string;
70	  communityId?: string;
71	}) {
72	  const page = filters.page || 1;
73	  const limit = filters.limit || 20;
74	  const skip = (page - 1) * limit;
75	
76	  const query: any = {};
77	  if (filters.search) {
78	    query.$or = [
79	      { firstName: { $regex: filters.search, $options: 'i' } },
80	      { lastName: { $regex: filters.search, $options: 'i' } },
81	    ];
82	  }
83	
84	  // Community isolation: if communityId is provided, only return users from that community
85	  let userFilter: any = {};
86	  if (filters.communityId) {
87	    const communityUsers = await User.find({ communityId: filters.communityId }).select('_id').lean();
88	    const userIds = communityUsers.map(u => u._id);
89	    query.userId = { $in: userIds };
90	  }
91	
92	  const [profiles, total] = await Promise.all([
93	    Profile.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit).lean(),
94	    Profile.countDocuments(query),
95	  ]);
96	
97	  // Minimize public fields — strip private data from list results
98	  const minimized = profiles.map(p => ({
99	    _id: p._id,
100	    userId: p.userId,
101	    firstName: p.firstName,
102	    lastName: p.lastName,
103	    displayName: (p as any).displayName,
104	    createdAt: (p as any).createdAt,
105	  }));
106	
107	  return { profiles: minimized, total, page, limit };
108	}
