117	/**
118	 * Get a profile with privacy rules applied based on the viewer's identity.
119	 */
120	export async function getProfileWithPrivacy(
121	  targetUserId: string,
122	  viewer: ProfileViewer
123	) {
124	  const profile = await Profile.findOne({ userId: targetUserId });
125	  if (!profile) {
126	    throw new NotFoundError('Profile not found');
127	  }
128	
129	  const targetUser = await User.findById(targetUserId);
130	  if (!targetUser) {
131	    throw new NotFoundError('User not found');
132	  }
133	
134	  // Owner or admin sees everything
135	  if (viewer.userId === targetUserId || viewer.role === Role.ADMIN) {
136	    return profile.toObject();
137	  }
138	
139	  const profileObj = profile.toObject() as any;
140	  const privacySettings = profileObj.privacySettings || {};
141	
142	  const privacyFields: string[] = [
143	    'firstName', 'lastName', 'phone', 'email', 'bio',
144	    'location', 'employer', 'graduationYear',
145	  ];
146	
147	  for (const field of privacyFields) {
148	    const level = (privacySettings as any)[field] as PrivacyLevel;
149	    const rawValue = (profileObj as any)[field];
150	
151	    if (rawValue === undefined || rawValue === null || rawValue === '') {
152	      continue;
153	    }
154	
155	    (profileObj as any)[field] = applyFieldPrivacy(
156	      field,
157	      String(rawValue),
158	      level,
159	      viewer.isAlumni,
160	      viewer.communityId,
161	      targetUser.communityId
162	    );
163	  }
164	
165	  return profileObj;
166	}
