10	export interface SubmitVerificationInput {
11	  photographerId: string;
12	  realName: string;
13	  qualificationType: string;
14	  issuingAuthority?: string;
15	  idDocumentPath: string;
16	  qualificationDocPaths: string[];
17	  fileChecksums: string[];
18	}
19	
20	export async function submitVerification(input: SubmitVerificationInput) {
21	  // Enforce first-use consent for government_id and qualification_documents
22	  const { checkConsent } = await import('./dataCategoryConsent.service');
23	  const { hasConsent: hasGovIdConsent } = await checkConsent(input.photographerId, 'government_id');
24	  if (!hasGovIdConsent) {
25	    throw new ForbiddenError('Consent for government_id data category is required before submitting verification');
26	  }
27	  const { hasConsent: hasQualConsent } = await checkConsent(input.photographerId, 'qualification_documents');
28	  if (!hasQualConsent) {
29	    throw new ForbiddenError('Consent for qualification_documents data category is required before submitting verification');
30	  }
31	
32	  // Encrypt sensitive fields
33	  const encryptedRealName = encrypt(input.realName, 'government_id');
34	  const encryptedIdDocPath = encrypt(input.idDocumentPath, 'government_id');
35	  const encryptedQualDocPaths = input.qualificationDocPaths.map(
36	    p => encrypt(p, 'qualification_documents')
37	  );
38	
39	  const verification = await Verification.create({
40	    photographerId: input.photographerId,
41	    realName: encryptedRealName,
42	    qualificationType: input.qualificationType,
43	    issuingAuthority: input.issuingAuthority,
44	    idDocumentPath: encryptedIdDocPath,
45	    qualificationDocPaths: encryptedQualDocPaths,
46	    status: VerificationStatus.SUBMITTED,
47	    submittedAt: new Date(),
48	    fileChecksums: input.fileChecksums,
49	  });
50	
51	  await logEvent({
52	    actorId: input.photographerId,
53	    action: AUDIT_EVENTS.KYC_SUBMIT,
54	    resource: 'verification',
55	    resourceId: verification._id.toString(),
56	    outcome: 'success',
57	  });
58	
59	  return verification;
60	}
