4	
5	async function assertJobParticipant(jobId: string, requesterId: string): Promise<void> {
6	  const job = await Job.findById(jobId);
7	  if (!job) throw new NotFoundError('Job not found');
8	  const requester = await User.findById(requesterId);
9	  if (requester?.role !== 'admin') {
10	    const isParticipant =
11	      job.clientId.toString() === requesterId ||
12	      (job.photographerId && job.photographerId.toString() === requesterId);
13	    if (!isParticipant) {
14	      throw new ForbiddenError('Only job participants can access escrow records');
15	    }
16	  }
17	}
18	
19	export async function addEntry(jobId: string, entryType: EscrowEntryType, amountCents: number, description: string, recordedBy: string) {
20	  await assertJobParticipant(jobId, recordedBy);
21	  const lastEntry = await EscrowLedger.findOne({ jobId }).sort({ createdAt: -1 });
22	  const prevBalance = lastEntry ? lastEntry.balanceCents : 0;
23	  let newBalance: number;
24	  if (entryType === EscrowEntryType.DEPOSIT) newBalance = prevBalance + amountCents;
25	  else if (entryType === EscrowEntryType.RELEASE || entryType === EscrowEntryType.REFUND) newBalance = prevBalance - amountCents;
26	  else newBalance = prevBalance + amountCents;
27	
28	  return EscrowLedger.create({ jobId, entryType, amountCents, balanceCents: newBalance, description, recordedBy });
29	}
30	
31	export async function getByJob(jobId: string, requesterId: string) {
32	  await assertJobParticipant(jobId, requesterId);
33	  return EscrowLedger.find({ jobId }).sort({ createdAt: 1 });
34	}
