1	import { Payment, Settlement, User } from '../models';
2	import { SettlementStatus, PaymentMethod } from '../types/enums';
3	import { NotFoundError, ValidationError, ForbiddenError } from '../utils/errors';
4	
5	async function assertSettlementParticipant(settlement: any, actorId: string): Promise<void> {
6	  const actor = await User.findById(actorId);
7	  if (actor?.role === 'admin') return;
8	  const isParticipant =
9	    settlement.clientId.toString() === actorId ||
10	    settlement.photographerId.toString() === actorId;
11	  if (!isParticipant) {
12	    throw new ForbiddenError('Only settlement participants or admins can record payments');
13	  }
14	}
15	
16	export interface RecordPaymentInput {
17	  settlementId: string;
18	  amountCents: number;
19	  method: PaymentMethod;
20	  receiptDetails: {
21	    referenceNumber?: string;
22	    date?: Date;
23	    notes?: string;
24	    attachmentId?: string;
25	  };
26	  recordedBy: string;
27	}
28	
29	export async function recordPayment(input: RecordPaymentInput) {
30	  const settlement = await Settlement.findById(input.settlementId);
31	  if (!settlement) {
32	    throw new NotFoundError('Settlement not found');
33	  }
34	
35	  await assertSettlementParticipant(settlement, input.recordedBy);
36	
37	  if (settlement.status !== SettlementStatus.APPROVED) {
38	    throw new ValidationError(
39	      `Cannot record payment for a settlement with status: ${settlement.status}. Must be approved.`
40	    );
41	  }
42	
43	  if (input.amountCents <= 0) {
44	    throw new ValidationError('Payment amount must be positive');
45	  }
46	
47	  const payment = await Payment.create({
48	    settlementId: input.settlementId,
49	    amountCents: input.amountCents,
50	    method: input.method,
51	    receiptDetails: {
52	      referenceNumber: input.receiptDetails.referenceNumber,
53	      date: input.receiptDetails.date || new Date(),
54	      notes: input.receiptDetails.notes,
55	      attachmentId: input.receiptDetails.attachmentId,
56	    },
57	    paidAt: new Date(),
58	    recordedBy: input.recordedBy,
59	  });
60	
61	  // Check if total paid matches or exceeds settlement
62	  const allPayments = await Payment.find({ settlementId: input.settlementId }).lean();
63	  const totalPaid = allPayments.reduce((sum, p) => sum + p.amountCents, 0);
64	
65	  if (totalPaid >= settlement.finalAmountCents) {
66	    settlement.status = SettlementStatus.PAID;
67	    await settlement.save();
68	  }
69	
70	  return payment;
71	}
