73	export async function getPaymentsBySettlement(settlementId: string, requesterId: string) {
74	  const { User } = await import('../models');
75	  const requester = await User.findById(requesterId);
76	  const requesterRole = requester?.role;
77	
78	  if (requesterRole !== 'admin') {
79	    const settlement = await Settlement.findById(settlementId);
80	    if (!settlement) throw new NotFoundError('Settlement not found');
81	    const isParticipant = settlement.clientId.toString() === requesterId || settlement.photographerId.toString() === requesterId;
82	    if (!isParticipant) throw new ForbiddenError('You do not have access to these payments');
83	  }
84	  return Payment.find({ settlementId }).sort({ paidAt: -1 }).lean();
85	}
