5	export function authorize(...roles: Role[]) {
6	  return (req: Request, _res: Response, next: NextFunction): void => {
7	    if (!req.user) {
8	      return next(new AuthError('Authentication required'));
9	    }
10	    if (roles.length > 0 && !roles.includes(req.user.role as Role)) {
11	      return next(new ForbiddenError('Insufficient permissions'));
12	    }
13	    next();
14	  };
15	}
