38	/**
39	 * Register a regular user, then promote to admin via direct DB update.
40	 * Uses mongoose from the server's node_modules.
41	 * Returns { token, userId }.
42	 */
43	async function createAdminUser() {
44	  const mongoose = require('/app/node_modules/mongoose');
45	  const ts = Date.now();
46	  const username = `admin_${ts}`;
47	  const email = `adm${ts}@t.com`;
48	
49	  // Register as a regular user first
50	  const res = await request('POST', '/api/auth/register', {
51	    username,
52	    email,
53	    password: 'AdminPass123!',
54	  });
55	
56	  if (res.status !== 201) {
57	    throw new Error(`Failed to register admin seed user: ${JSON.stringify(res.data)}`);
58	  }
59	
60	  const userId = res.data.user._id;
61	
62	  // Promote to admin directly in the DB via mongoose
63	  const conn = await mongoose.createConnection(MONGO_URI).asPromise();
64	  try {
65	    await conn.collection('users').updateOne(
66	      { _id: new mongoose.Types.ObjectId(userId) },
67	      { $set: { role: 'admin' } },
68	    );
69	  } finally {
70	    await conn.close();
71	  }
72	
73	  // Re-login to get a token with the updated role
74	  const loginRes = await request('POST', '/api/auth/login', { username, password: 'AdminPass123!' });
75	  return { token: loginRes.data.token, userId };
76	}
77	
78	module.exports = { request, createAdminUser, BASE };
