1	import { useState, useEffect } from 'react';
2	import { useParams, useNavigate } from 'react-router-dom';
3	import { portfoliosApi } from '../api/portfolios.api';
4	import { useAuth } from '../context/AuthContext';
5	import FileUpload from '../components/shared/FileUpload';
6	
7	export default function PortfolioUploadPage() {
8	  const { id } = useParams<{ id: string }>();
9	  const navigate = useNavigate();
10	  const { user } = useAuth();
11	  const [portfolios, setPortfolios] = useState<any[]>([]);
12	  const [selectedPortfolio, setSelectedPortfolio] = useState(id || '');
13	  const [files, setFiles] = useState<File[]>([]);
14	  const [copyrightNotice, setCopyrightNotice] = useState('');
15	  const [caption, setCaption] = useState('');
16	  const [uploading, setUploading] = useState(false);
17	  const [error, setError] = useState('');
18	  const [success, setSuccess] = useState('');
19	
20	  // New portfolio form
21	  const [showCreate, setShowCreate] = useState(false);
22	  const [newPortfolio, setNewPortfolio] = useState({ title: '', description: '', specialties: '' });
23	
24	  useEffect(() => {
25	    portfoliosApi.getAll({ photographerId: user?._id })
26	      .then(res => {
27	        const items = res.data.items || res.data || [];
28	        setPortfolios(items);
29	        if (!selectedPortfolio && items.length > 0) setSelectedPortfolio(items[0]._id);
30	      })
31	      .catch(() => {});
32	  }, [user]);
33	
34	  const handleCreatePortfolio = async (e: React.FormEvent) => {
35	    e.preventDefault();
36	    setError('');
37	    try {
38	      const res = await portfoliosApi.create({
39	        title: newPortfolio.title,
40	        description: newPortfolio.description,
41	        specialties: newPortfolio.specialties.split(',').map(s => s.trim()).filter(Boolean),
42	      });
43	      const created = res.data;
44	      setPortfolios([...portfolios, created]);
45	      setSelectedPortfolio(created._id);
46	      setShowCreate(false);
47	      setNewPortfolio({ title: '', description: '', specialties: '' });
48	    } catch (err: any) {
49	      setError(err.response?.data?.msg || 'Failed to create portfolio');
50	    }
51	  };
52	
53	  const handleUpload = async (e: React.FormEvent) => {
54	    e.preventDefault();
55	    if (!selectedPortfolio || files.length === 0) {
56	      setError('Please select a portfolio and at least one file.');
57	      return;
58	    }
59	    setUploading(true);
60	    setError('');
61	    setSuccess('');
62	    try {
63	      for (const file of files) {
64	        const formData = new FormData();
65	        formData.append('image', file);
66	        formData.append('copyrightNotice', copyrightNotice);
67	        formData.append('caption', caption);
68	        await portfoliosApi.addImage(selectedPortfolio, formData);
69	      }
70	      setSuccess(`${files.length} image(s) uploaded successfully.`);
71	      setFiles([]);
72	      setCaption('');
73	      setTimeout(() => navigate(`/portfolios/${selectedPortfolio}`), 1500);
74	    } catch (err: any) {
75	      setError(err.response?.data?.msg || 'Failed to upload images');
76	    } finally {
77	      setUploading(false);
78	    }
79	  };
80	
81	  return (
82	    <div className="max-w-2xl mx-auto">
83	      <h1 className="text-2xl font-bold mb-6">Upload Portfolio Images</h1>
84	      {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm">{error}</div>}
85	      {success && <div className="bg-green-50 text-green-600 p-3 rounded mb-4 text-sm">{success}</div>}
86	
87	      <form onSubmit={handleUpload} className="bg-white rounded-lg shadow p-6 space-y-5">
88	        <div>
89	          <label className="block text-sm font-medium text-gray-700 mb-1">Portfolio</label>
90	          <div className="flex gap-2">
91	            <select
92	              value={selectedPortfolio}
93	              onChange={e => setSelectedPortfolio(e.target.value)}
94	              className="flex-1 border rounded px-3 py-2 text-sm"
95	            >
96	              <option value="">Select a portfolio...</option>
97	              {portfolios.map(p => (
98	                <option key={p._id} value={p._id}>{p.title}</option>
99	              ))}
100	            </select>
101	            <button type="button" onClick={() => setShowCreate(!showCreate)} className="border px-3 py-2 rounded text-sm hover:bg-gray-50">
102	              {showCreate ? 'Cancel' : '+ New'}
103	            </button>
104	          </div>
105	        </div>
106	
107	        {showCreate && (
108	          <div className="border rounded p-4 bg-gray-50 space-y-3">
109	            <input type="text" placeholder="Portfolio title" value={newPortfolio.title} onChange={e => setNewPortfolio({ ...newPortfolio, title: e.target.value })} required className="w-full border rounded px-3 py-2 text-sm" />
110	            <input type="text" placeholder="Description" value={newPortfolio.description} onChange={e => setNewPortfolio({ ...newPortfolio, description: e.target.value })} className="w-full border rounded px-3 py-2 text-sm" />
111	            <input type="text" placeholder="Specialties (comma-separated)" value={newPortfolio.specialties} onChange={e => setNewPortfolio({ ...newPortfolio, specialties: e.target.value })} className="w-full border rounded px-3 py-2 text-sm" />
112	            <button type="button" onClick={handleCreatePortfolio} className="bg-primary-600 text-white px-4 py-1.5 rounded text-sm hover:bg-primary-700">Create Portfolio</button>
113	          </div>
114	        )}
115	
116	        <FileUpload
117	          onFilesSelected={setFiles}
118	          accept=".jpg,.jpeg,.png"
119	          multiple={true}
120	          label="Images"
121	          maxSizeMB={10}
122	        />
123	
124	        <div>
125	          <label className="block text-sm font-medium text-gray-700 mb-1">Caption</label>
126	          <input type="text" value={caption} onChange={e => setCaption(e.target.value)} className="w-full border rounded px-3 py-2 text-sm" placeholder="Optional caption for all images" />
127	        </div>
128	
129	        <div>
130	          <label className="block text-sm font-medium text-gray-700 mb-1">Copyright Notice *</label>
131	          <input
132	            type="text"
133	            value={copyrightNotice}
134	            onChange={e => setCopyrightNotice(e.target.value)}
135	            required
136	            className="w-full border rounded px-3 py-2 text-sm"
137	            placeholder="e.g., (c) 2026 John Smith. All rights reserved."
138	          />
139	          <p className="text-xs text-gray-500 mt-1">You must have the rights to upload these images.</p>
140	        </div>
141	
142	        <button type="submit" disabled={uploading || files.length === 0} className="bg-primary-600 text-white px-6 py-2 rounded hover:bg-primary-700 disabled:opacity-50 text-sm">
143	          {uploading ? 'Uploading...' : `Upload ${files.length} Image(s)`}
144	        </button>
145	      </form>
146	    </div>
147	  );
148	}
