describe('Deliverable Upload - Auth & Validation (F-01)', () => {
  let photographerToken, photographerId;
  let alumniToken, alumniId;
  let adminToken;
  let jobId;

  beforeAll(async () => {
    const ts = Date.now();

    // Register a photographer
    const photog = await request('POST', '/api/auth/register', {
      username: `delPhotog_${ts}`, email: `dp${ts}@t.com`, password: 'PhotPass123!', role: 'photographer',
    });
    photographerToken = photog.data.token;
    photographerId = photog.data.user._id;

    // Register an alumni (client)
    const alumni = await request('POST', '/api/auth/register', {
      username: `delAlumni_${ts}`, email: `da${ts}@t.com`, password: 'AlumPass123!',
    });
    alumniToken = alumni.data.token;
    alumniId = alumni.data.user._id;

    // Create admin
    const admin = await createAdminUser();
    adminToken = admin.token;

    // Alumni creates a job and admin assigns the photographer
    const job = await request('POST', '/api/jobs', {
      title: 'Deliverable Test Job', description: 'Testing deliverable upload',
      jobType: 'event', rateType: 'hourly', agreedRateCents: 5000, estimatedTotalCents: 10000,
    }, alumniToken);
    jobId = job.data._id;

    // Assign photographer via admin
    await request('PATCH', `/api/jobs/${jobId}/assign`, { photographerId }, adminToken);
  });

  test('Alumni (non-photographer) cannot upload deliverables', async () => {
    const http = require('http');
    const crypto = require('crypto');
    const boundary = '----TestBound' + Date.now();
    // Build a minimal multipart body with a valid JPEG
    const jpegHeader = Buffer.from([0xFF, 0xD8, 0xFF, 0xE0]);
    const fileContent = Buffer.concat([jpegHeader, Buffer.alloc(100, 0x00)]);
    const body = Buffer.concat([
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="copyrightNotice"\r\n\r\nTest copyright\r\n`),
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="test.jpg"\r\nContent-Type: image/jpeg\r\n\r\n`),
      fileContent,
      Buffer.from(`\r\n--${boundary}--`),
    ]);

    const res = await new Promise((resolve, reject) => {
      const url = new URL(`/api/jobs/${jobId}/deliverables`, process.env.API_BASE || 'http://server:3001');
      const req = http.request({
        hostname: url.hostname, port: url.port, path: url.pathname, method: 'POST',
        headers: {
          'Content-Type': `multipart/form-data; boundary=${boundary}`,
          'Content-Length': body.length,
          'Authorization': `Bearer ${alumniToken}`,
          'X-Nonce': crypto.randomUUID(),
          'X-Timestamp': Date.now().toString(),
        },
      }, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
          catch { resolve({ status: res.statusCode, data }); }
        });
      });
      req.on('error', reject);
      req.write(body);
      req.end();
    });
    expect(res.status).toBe(403);
  });

  test('Upload without copyrightNotice is rejected with 400', async () => {
    const http = require('http');
    const crypto = require('crypto');
    const boundary = '----TestBound' + Date.now();
    const jpegHeader = Buffer.from([0xFF, 0xD8, 0xFF, 0xE0]);
    const fileContent = Buffer.concat([jpegHeader, Buffer.alloc(100, 0x00)]);
    // Omit copyrightNotice field
    const body = Buffer.concat([
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="test.jpg"\r\nContent-Type: image/jpeg\r\n\r\n`),
      fileContent,
      Buffer.from(`\r\n--${boundary}--`),
    ]);

    const res = await new Promise((resolve, reject) => {
      const url = new URL(`/api/jobs/${jobId}/deliverables`, process.env.API_BASE || 'http://server:3001');
      const req = http.request({
        hostname: url.hostname, port: url.port, path: url.pathname, method: 'POST',
        headers: {
          'Content-Type': `multipart/form-data; boundary=${boundary}`,
          'Content-Length': body.length,
          'Authorization': `Bearer ${photographerToken}`,
          'X-Nonce': crypto.randomUUID(),
          'X-Timestamp': Date.now().toString(),
        },
      }, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
          catch { resolve({ status: res.statusCode, data }); }
        });
      });
      req.on('error', reject);
      req.write(body);
      req.end();
    });
    expect(res.status).toBe(400);
  });

  test('Unauthenticated deliverable upload is rejected with 401', async () => {
    const res = await request('POST', `/api/jobs/${jobId}/deliverables`, {});
    expect(res.status).toBe(401);
  });

  test('GET deliverables by non-participant is rejected with 403', async () => {
    const ts = Date.now();
    const outsider = await request('POST', '/api/auth/register', {
      username: `delOut_${ts}`, email: `do${ts}@t.com`, password: 'OutPass123!',
    });
    const res = await request('GET', `/api/jobs/${jobId}/deliverables`, null, outsider.data.token);
    expect(res.status).toBe(403);
  });

  test('Assigned photographer can view deliverables', async () => {
    const res = await request('GET', `/api/jobs/${jobId}/deliverables`, null, photographerToken);
    expect(res.status).toBe(200);
    expect(Array.isArray(res.data)).toBe(true);
  });

  test('Admin can view deliverables for any job', async () => {
    const res = await request('GET', `/api/jobs/${jobId}/deliverables`, null, adminToken);
    expect(res.status).toBe(200);
  });
});
"}

