{"file_path": "/Users/macbookpro/Projects/eaglepoint/TASK-24/repo/API_tests/consent.test.js", "content": "const { request, createAdminUser } = require('./helpers');

describe('Consent Contract Enforcement (F-02)', () => {
  let userToken, userId;
  let adminToken;
  let policyVersion;

  beforeAll(async () => {
    const ts = Date.now();
    const user = await request('POST', '/api/auth/register', {
      username: `conUser_${ts}`, email: `cu${ts}@t.com`, password: 'ConPass123!',
    });
    userToken = user.data.token;
    userId = user.data.user._id;

    const admin = await createAdminUser();
    adminToken = admin.token;

    // Create a privacy policy so we have a valid version
    policyVersion = `v_${ts}`;
    await request('POST', '/api/admin/privacy-policies', {
      version: policyVersion,
      content: 'Test policy for consent tests',
      effectiveDate: new Date().toISOString(),
      purposes: ['general'],
    }, adminToken);
  });

  // --- Policy consent contract ---

  test('Recording consent with policyVersion succeeds', async () => {
    const res = await request('POST', '/api/consent', {
      policyVersion,
      accepted: true,
    }, userToken);
    expect(res.status).toBe(201);
    expect(res.data.policyVersion).toBe(policyVersion);
  });

  test('Recording consent without policyVersion is rejected', async () => {
    const res = await request('POST', '/api/consent', {
      accepted: true,
    }, userToken);
    expect(res.status).toBe(400);
  });

  test('Recording consent with invalid (non-existent) policyVersion is rejected', async () => {
    const res = await request('POST', '/api/consent', {
      policyVersion: 'nonexistent_version_999',
      accepted: true,
    }, userToken);
    expect(res.status).toBe(404);
  });

  // --- Data category consent ---

  test('Granting consent for valid data category succeeds', async () => {
    const res = await request('POST', '/api/consent/data-category', {
      category: 'contact_information',
    }, userToken);
    expect(res.status).toBe(201);
  });

  test('Granting consent for invalid data category is rejected', async () => {
    const res = await request('POST', '/api/consent/data-category', {
      category: 'invalid_category_xxx',
    }, userToken);
    expect(res.status).toBe(400);
  });

  test('Active category consents are returned', async () => {
    const res = await request('GET', '/api/consent/data-category', null, userToken);
    expect(res.status).toBe(200);
    const categories = (res.data.items || res.data || []);
    expect(Array.isArray(categories)).toBe(true);
    const contactConsent = categories.find(c => c.dataCategory === 'contact_information');
    expect(contactConsent).toBeDefined();
  });

  test('Revoking consent for valid active category succeeds', async () => {
    const res = await request('DELETE', '/api/consent/data-category/contact_information', null, userToken);
    expect(res.status).toBe(200);
  });

  test('Revoking consent for invalid category is rejected', async () => {
    const res = await request('DELETE', '/api/consent/data-category/invalid_xxx', null, userToken);
    expect(res.status).toBe(400);
  });

  test('Revoking consent for already-revoked category is rejected', async () => {
    const res = await request('DELETE', '/api/consent/data-category/contact_information', null, userToken);
    expect(res.status).toBe(404);
  });

  // --- Consent history ---

  test('Consent history is returned for authenticated user', async () => {
    const res = await request('GET', '/api/consent/history', null, userToken);
    expect(res.status).toBe(200);
    expect(Array.isArray(res.data)).toBe(true);
  });

  test('Consent current-policy check returns structured response', async () => {
    const res = await request('GET', '/api/consent/current-policy', null, userToken);
    expect(res.status).toBe(200);
    expect(res.data).toHaveProperty('isCurrent');
    expect(res.data).toHaveProperty('needsReconsent');
  });

  // --- All valid data categories ---

  const validCategories = [
    'account_identity',
    'contact_information',
    'employer_information',
    'government_id',
    'tax_forms',
    'qualification_documents',
    'device_fingerprint',
  ];

  test.each(validCategories)('Category "%s" is accepted', async (category) => {
    const res = await request('POST', '/api/consent/data-category', { category }, userToken);
    expect(res.status).toBe(201);
  });
});
"}

