    expect(contactConsent).toBeDefined();
  });

  test('Revoking consent for valid active category succeeds', async () => {
    const res = await request('DELETE', '/api/consent/data-category/contact_information', null, userToken);
    expect(res.status).toBe(200);
  });

  test('Revoking consent for invalid category is rejected', async () => {
    const res = await request('DELETE', '/api/consent/data-category/invalid_xxx', null, userToken);
    expect(res.status).toBe(400);
  });

  test('Revoking consent for already-revoked category is rejected', async () => {
    const res = await request('DELETE', '/api/consent/data-category/contact_information', null, userToken);
    expect(res.status).toBe(404);
  });

  // --- Consent history ---

  test('Consent history is returned for authenticated user', async () => {
    const res = await request('GET', '/api/consent/history', null, userToken);
    expect(res.status).toBe(200);
    expect(Array.isArray(res.data)).toBe(true);
  });

  test('Consent current-policy check returns structured response', async () => {
    const res = await request('GET', '/api/consent/current-policy', null, userToken);
    expect(res.status).toBe(200);
    expect(res.data).toHaveProperty('isCurrent');
    expect(res.data).toHaveProperty('needsReconsent');
  });

  // --- All valid data categories ---

  const validCategories = [
    'account_identity',
    'contact_information',
    'employer_information',
    'government_id',
    'tax_forms',
    'qualification_documents',
    'device_fingerprint',
  ];

  test.each(validCategories)('Category "%s" is accepted', async (category) => {
    const res = await request('POST', '/api/consent/data-category', { category }, userToken);
    expect(res.status).toBe(201);
  });
});
"}

