1	import sharp from 'sharp';
2	import path from 'path';
3	
4	export interface WatermarkOptions {
5	  text: string;
6	  fontSize?: number;
7	  opacity?: number;
8	  color?: string;
9	  position?: 'center' | 'bottom-right' | 'bottom-left';
10	}
11	
12	/**
13	 * Apply a text watermark overlay to an image buffer using sharp.
14	 * Returns the watermarked image buffer.
15	 */
16	export async function applyWatermark(
17	  inputBuffer: Buffer,
18	  options: WatermarkOptions
19	): Promise<Buffer> {
20	  const {
21	    text,
22	    fontSize = 48,
23	    opacity = 0.3,
24	    color = 'white',
25	    position = 'center',
26	  } = options;
27	
28	  const image = sharp(inputBuffer);
29	  const metadata = await image.metadata();
30	
31	  const width = metadata.width || 800;
32	  const height = metadata.height || 600;
33	
34	  // Calculate watermark text positioning
35	  let x: number;
36	  let y: number;
37	
38	  switch (position) {
39	    case 'bottom-right':
40	      x = Math.max(width - fontSize * text.length * 0.5 - 20, 20);
41	      y = height - fontSize - 20;
42	      break;
43	    case 'bottom-left':
44	      x = 20;
45	      y = height - fontSize - 20;
46	      break;
47	    case 'center':
48	    default:
49	      x = Math.max((width - fontSize * text.length * 0.5) / 2, 0);
50	      y = (height - fontSize) / 2;
51	      break;
52	  }
53	
54	  const opacityHex = Math.round(opacity * 255).toString(16).padStart(2, '0');
55	  const fillColor = color === 'white' ? `#ffffff${opacityHex}` : `#000000${opacityHex}`;
56	
57	  const svgOverlay = Buffer.from(
58	    `<svg width="${width}" height="${height}">
59	      <text
60	        x="${x}"
61	        y="${y}"
62	        font-size="${fontSize}"
63	        fill="${fillColor}"
64	        font-family="sans-serif"
65	        font-weight="bold"
66	      >${escapeXml(text)}</text>
67	    </svg>`
68	  );
69	
70	  const result = await image
71	    .composite([
72	      {
73	        input: svgOverlay,
74	        top: 0,
75	        left: 0,
76	      },
77	    ])
78	    .toBuffer();
79	
80	  return result;
81	}
82	
83	function escapeXml(text: string): string {
84	  return text
85	    .replace(/&/g, '&amp;')
86	    .replace(/</g, '&lt;')
87	    .replace(/>/g, '&gt;')
88	    .replace(/"/g, '&quot;')
89	    .replace(/'/g, '&apos;');
90	}
