1	import { useEffect, useState } from 'react';
2	import { useParams, Link } from 'react-router-dom';
3	import { jobsApi } from '../api/jobs.api';
4	import { useAuth } from '../context/AuthContext';
5	import { formatCents, formatDateTime } from '../utils/formatters';
6	import LoadingSpinner from '../components/shared/LoadingSpinner';
7	import MoneyDisplay from '../components/shared/MoneyDisplay';
8	
9	export default function EscrowLedgerPage() {
10	  const { jobId } = useParams<{ jobId: string }>();
11	  const { user } = useAuth();
12	  const [escrow, setEscrow] = useState<any>(null);
13	  const [job, setJob] = useState<any>(null);
14	  const [loading, setLoading] = useState(true);
15	  const [error, setError] = useState('');
16	  const [showForm, setShowForm] = useState(false);
17	  const [form, setForm] = useState({ amountDollars: '', description: '' });
18	  const [saving, setSaving] = useState(false);
19	
20	  const fetchData = async () => {
21	    if (!jobId) return;
22	    try {
23	      const [jobRes, escrowRes] = await Promise.all([
24	        jobsApi.getById(jobId),
25	        jobsApi.getEscrow(jobId),
26	      ]);
27	      setJob(jobRes.data);
28	      setEscrow(escrowRes.data);
29	    } catch (err: any) {
30	      setError(err.response?.data?.msg || 'Failed to load escrow data');
31	    } finally {
32	      setLoading(false);
33	    }
34	  };
35	
36	  useEffect(() => { fetchData(); }, [jobId]);
37	
38	  const handleAddEscrow = async (e: React.FormEvent) => {
39	    e.preventDefault();
40	    if (!jobId) return;
41	    setSaving(true);
42	    setError('');
43	    try {
44	      await jobsApi.addEscrow(jobId, {
45	        amountCents: Math.round(parseFloat(form.amountDollars) * 100),
46	        description: form.description,
47	      });
48	      setShowForm(false);
49	      setForm({ amountDollars: '', description: '' });
50	      await fetchData();
51	    } catch (err: any) {
52	      setError(err.response?.data?.msg || 'Failed to add escrow');
53	    } finally {
54	      setSaving(false);
55	    }
56	  };
57	
58	  if (loading) return <LoadingSpinner message="Loading escrow ledger..." />;
59	
60	  const transactions = escrow?.transactions || escrow?.entries || [];
61	  const balance = escrow?.balance || escrow?.balanceCents || 0;
62	  const isClient = user?._id === job?.clientId;
63	
64	  return (
65	    <div className="max-w-3xl mx-auto">
66	      <div className="flex items-center justify-between mb-6">
67	        <div>
68	          <h1 className="text-2xl font-bold">Escrow Ledger</h1>
69	          {job && <p className="text-sm text-gray-500 mt-1">Job: <Link to={`/jobs/${jobId}`} className="text-primary-600 hover:underline">{job.title}</Link></p>}
70	        </div>
71	        {isClient && (
72	          <button onClick={() => setShowForm(!showForm)} className="bg-primary-600 text-white px-4 py-2 rounded text-sm hover:bg-primary-700">
73	            {showForm ? 'Cancel' : 'Add Funds'}
74	          </button>
75	        )}
76	      </div>
77	      {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm">{error}</div>}
78	
79	      <div className="bg-white rounded-lg shadow p-6 mb-6">
80	        <div className="text-center">
81	          <p className="text-sm text-gray-500">Current Balance</p>
82	          <p className="text-3xl font-bold mt-1"><MoneyDisplay cents={balance} /></p>
83	        </div>
84	      </div>
85	
86	      {showForm && (
87	        <form onSubmit={handleAddEscrow} className="bg-white rounded-lg shadow p-6 mb-6 space-y-4">
88	          <div className="grid grid-cols-2 gap-4">
89	            <div>
90	              <label className="block text-sm font-medium text-gray-700 mb-1">Amount ($)</label>
91	              <input type="number" step="0.01" min="0.01" value={form.amountDollars} onChange={e => setForm({ ...form, amountDollars: e.target.value })} required className="w-full border rounded px-3 py-2 text-sm" />
92	            </div>
93	            <div>
94	              <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
95	              <input type="text" value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} required className="w-full border rounded px-3 py-2 text-sm" placeholder="e.g., Initial deposit" />
96	            </div>
97	          </div>
98	          <button type="submit" disabled={saving} className="bg-primary-600 text-white px-4 py-2 rounded text-sm hover:bg-primary-700 disabled:opacity-50">
99	            {saving ? 'Adding...' : 'Add Escrow Funds'}
100	          </button>
101	        </form>
102	      )}
103	
104	      <div className="bg-white rounded-lg shadow overflow-hidden">
105	        <div className="px-6 py-4 border-b">
106	          <h2 className="font-semibold">Transactions</h2>
107	        </div>
108	        {transactions.length === 0 ? (
109	          <p className="p-6 text-sm text-gray-500">No escrow transactions yet.</p>
110	        ) : (
111	          <table className="w-full text-sm">
112	            <thead>
113	              <tr className="border-b bg-gray-50">
114	                <th className="text-left px-6 py-3">Date</th>
115	                <th className="text-left px-6 py-3">Description</th>
116	                <th className="text-right px-6 py-3">Amount</th>
117	                <th className="text-right px-6 py-3">Running Balance</th>
118	              </tr>
119	            </thead>
120	            <tbody>
121	              {transactions.map((tx: any, i: number) => (
122	                <tr key={tx._id || i} className="border-b">
123	                  <td className="px-6 py-3">{formatDateTime(tx.createdAt || tx.date)}</td>
124	                  <td className="px-6 py-3 text-gray-600">{tx.description || tx.type || '-'}</td>
125	                  <td className="px-6 py-3 text-right"><MoneyDisplay cents={tx.amountCents || 0} showSign /></td>
126	                  <td className="px-6 py-3 text-right font-mono">{tx.runningBalance != null ? formatCents(tx.runningBalance) : '-'}</td>
127	                </tr>
128	              ))}
129	            </tbody>
130	          </table>
131	        )}
132	      </div>
133	    </div>
134	  );
135	}
