const http = require('http');
const crypto = require('crypto');

describe('Portfolio - Data Contract & Watermark Flow', () => {
  let photographerToken, photographerId;
  let alumniToken;
  let portfolioId;

  beforeAll(async () => {
    const ts = Date.now();
    const photog = await request('POST', '/api/auth/register', {
      username: `portPhotog_${ts}`, email: `pp${ts}@t.com`, password: 'PhotPass123!', role: 'photographer',
    });
    photographerToken = photog.data.token;
    photographerId = photog.data.user._id;

    const alumni = await request('POST', '/api/auth/register', {
      username: `portAlumni_${ts}`, email: `pa${ts}@t.com`, password: 'AlumPass123!',
    });
    alumniToken = alumni.data.token;

    // Create a portfolio
    const port = await request('POST', '/api/portfolios', {
      title: 'Watermark Test Portfolio',
      description: 'Testing watermark integration',
    }, photographerToken);
    portfolioId = port.data._id;
  });

  test('Portfolio creation returns valid structure', async () => {
    expect(portfolioId).toBeDefined();
    const res = await request('GET', `/api/portfolios/${portfolioId}`, null, photographerToken);
    expect(res.status).toBe(200);
    expect(res.data.title).toBe('Watermark Test Portfolio');
    expect(res.data.images).toBeDefined();
    expect(Array.isArray(res.data.images)).toBe(true);
  });

  test('Portfolio detail response includes images array', async () => {
    const res = await request('GET', `/api/portfolios/${portfolioId}`, null, photographerToken);
    expect(res.status).toBe(200);
    expect(res.data).toHaveProperty('images');
    expect(Array.isArray(res.data.images)).toBe(true);
  });

  test('Portfolio list returns portfolios array', async () => {
    const res = await request('GET', '/api/portfolios', null, photographerToken);
    expect(res.status).toBe(200);
    expect(res.data.portfolios).toBeDefined();
    expect(Array.isArray(res.data.portfolios)).toBe(true);
  });

  test('Image upload with watermark fields stores watermarkEnabled and copyrightNotice', async () => {
    // Upload a minimal valid JPEG with watermark fields
    const boundary = '----TestBound' + Date.now();
    // Minimal JPEG: FF D8 FF E0 ... FF D9
    const jpegHeader = Buffer.from([0xFF, 0xD8, 0xFF, 0xE0, 0x00, 0x10, 0x4A, 0x46, 0x49, 0x46, 0x00]);
    const jpegFooter = Buffer.from([0xFF, 0xD9]);
    const jpegContent = Buffer.concat([jpegHeader, Buffer.alloc(100, 0x00), jpegFooter]);

    const body = Buffer.concat([
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="copyrightNotice"\r\n\r\nTest Copyright 2026\r\n`),
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="caption"\r\n\r\nTest caption\r\n`),
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="watermarkEnabled"\r\n\r\ntrue\r\n`),
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="image"; filename="test.jpg"\r\nContent-Type: image/jpeg\r\n\r\n`),
      jpegContent,
      Buffer.from(`\r\n--${boundary}--`),
    ]);

    const res = await new Promise((resolve, reject) => {
      const url = new URL(`/api/portfolios/${portfolioId}/images`, process.env.API_BASE || 'http://server:3001');
      const req = http.request({
        hostname: url.hostname, port: url.port, path: url.pathname, method: 'POST',
        headers: {
          'Content-Type': `multipart/form-data; boundary=${boundary}`,
          'Content-Length': body.length,
          'Authorization': `Bearer ${photographerToken}`,
          'X-Nonce': crypto.randomUUID(),
          'X-Timestamp': Date.now().toString(),
        },
      }, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
          catch { resolve({ status: res.statusCode, data }); }
        });
      });
      req.on('error', reject);
      req.write(body);
      req.end();
    });

    expect(res.status).toBe(201);
    expect(res.data.watermarkEnabled).toBe(true);
    expect(res.data.copyrightNotice).toBe('Test Copyright 2026');
    expect(res.data.caption).toBe('Test caption');
    expect(res.data.originalPath).toBeDefined();
    expect(res.data.previewPath).toBeDefined();
  });

  test('Portfolio detail now includes uploaded image', async () => {
    const res = await request('GET', `/api/portfolios/${portfolioId}`, null, photographerToken);
    expect(res.status).toBe(200);
    expect(res.data.images.length).toBeGreaterThan(0);
    const img = res.data.images[0];
    expect(img.watermarkEnabled).toBe(true);
    expect(img.copyrightNotice).toBe('Test Copyright 2026');
  });

  test('GET /:id/images endpoint returns images separately', async () => {
    const res = await request('GET', `/api/portfolios/${portfolioId}/images`, null, photographerToken);
    expect(res.status).toBe(200);
    const images = res.data.images || res.data;
    expect(Array.isArray(images)).toBe(true);
    expect(images.length).toBeGreaterThan(0);
  });

  test('Non-photographer cannot upload to a portfolio', async () => {
    const boundary = '----TestBound' + Date.now();
    const jpegContent = Buffer.from([0xFF, 0xD8, 0xFF, 0xE0, 0x00, 0x10]);
    const body = Buffer.concat([
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="image"; filename="test.jpg"\r\nContent-Type: image/jpeg\r\n\r\n`),
      jpegContent,
      Buffer.from(`\r\n--${boundary}--`),
    ]);

    const res = await new Promise((resolve, reject) => {
      const url = new URL(`/api/portfolios/${portfolioId}/images`, process.env.API_BASE || 'http://server:3001');
      const req = http.request({
        hostname: url.hostname, port: url.port, path: url.pathname, method: 'POST',
        headers: {
          'Content-Type': `multipart/form-data; boundary=${boundary}`,
          'Content-Length': body.length,
          'Authorization': `Bearer ${alumniToken}`,
          'X-Nonce': crypto.randomUUID(),
          'X-Timestamp': Date.now().toString(),
        },
      }, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
          catch { resolve({ status: res.statusCode, data }); }
        });
      });
      req.on('error', reject);
      req.write(body);
      req.end();
    });
    expect(res.status).toBe(403);
  });

  test('Image upload with watermarkEnabled=false stores watermarkEnabled false', async () => {
    const boundary = '----TestBound' + Date.now();
    const jpegHeader = Buffer.from([0xFF, 0xD8, 0xFF, 0xE0, 0x00, 0x10, 0x4A, 0x46, 0x49, 0x46, 0x00]);
    const jpegFooter = Buffer.from([0xFF, 0xD9]);
    const jpegContent = Buffer.concat([jpegHeader, Buffer.alloc(100, 0x00), jpegFooter]);

    const body = Buffer.concat([
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="copyrightNotice"\r\n\r\nNo watermark test\r\n`),
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="watermarkEnabled"\r\n\r\nfalse\r\n`),
      Buffer.from(`--${boundary}\r\nContent-Disposition: form-data; name="image"; filename="nowm.jpg"\r\nContent-Type: image/jpeg\r\n\r\n`),
      jpegContent,
      Buffer.from(`\r\n--${boundary}--`),
    ]);

    const res = await new Promise((resolve, reject) => {
      const url = new URL(`/api/portfolios/${portfolioId}/images`, process.env.API_BASE || 'http://server:3001');
      const req = http.request({
        hostname: url.hostname, port: url.port, path: url.pathname, method: 'POST',
        headers: {
          'Content-Type': `multipart/form-data; boundary=${boundary}`,
          'Content-Length': body.length,
          'Authorization': `Bearer ${photographerToken}`,
          'X-Nonce': crypto.randomUUID(),
          'X-Timestamp': Date.now().toString(),
        },
      }, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
          catch { resolve({ status: res.statusCode, data }); }
        });
      });
      req.on('error', reject);
      req.write(body);
      req.end();
    });

    expect(res.status).toBe(201);
    expect(res.data.watermarkEnabled).toBe(false);
    // When watermark is disabled, preview should equal original
    expect(res.data.previewPath).toBe(res.data.originalPath);
  });

  test('Image removal by owner succeeds', async () => {
    // Get images first
    const listRes = await request('GET', `/api/portfolios/${portfolioId}/images`, null, photographerToken);
    const images = listRes.data.images || listRes.data;
    expect(images.length).toBeGreaterThan(0);

    const imageId = images[0]._id;
    const delRes = await request('DELETE', `/api/portfolios/${portfolioId}/images/${imageId}`, null, photographerToken);
    expect(delRes.status).toBe(200);
  });
});
"}

