  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [deleting, setDeleting] = useState('');

  useEffect(() => {
    // Reset all view state when id changes to prevent stale data across views
    setPortfolio(null);
    setPortfolios([]);
    setImages([]);
    setLoading(true);
    setError('');

    if (id) {
      // Detail view: fetch portfolio then images
      const loadDetail = async () => {
        try {
          const pRes = await portfoliosApi.getById(id);
          setPortfolio(pRes.data);

          // Use images embedded in detail response when available
          const embedded = pRes.data.images;
          if (Array.isArray(embedded) && embedded.length > 0) {
            setImages(embedded);
          } else {
            // Fall back to dedicated images endpoint
            const iRes = await portfoliosApi.getImages(id).catch(() => ({ data: [] }));
            setImages(iRes.data.images || iRes.data || []);
          }
        } catch (err: any) {
          setError(err.response?.data?.msg || 'Failed to load portfolio');
        } finally {
          setLoading(false);
        }
      };
      loadDetail();
    } else {
      // List view
      portfoliosApi.getAll()
        .then(res => setPortfolios(res.data.portfolios || res.data || []))
        .catch(err => setError(err.response?.data?.msg || 'Failed to load portfolios'))
        .finally(() => setLoading(false));
    }
  }, [id]);

  const handleRemoveImage = async (imageId: string) => {
    if (!id || !confirm('Remove this image?')) return;
    setDeleting(imageId);
    try {
      await portfoliosApi.removeImage(id, imageId);
      const iRes = await portfoliosApi.getImages(id).catch(() => ({ data: [] }));
      setImages(iRes.data.images || iRes.data || []);
    } catch (err: any) {
      setError(err.response?.data?.msg || 'Failed to remove image');
    } finally {
      setDeleting('');
    }
  };

  if (loading) return <LoadingSpinner message={id ? 'Loading portfolio...' : 'Loading portfolios...'} />;

  // List view when no ID
  if (!id) {
    return (
      <div>
        <div className="flex items-center justify-between mb-6">
          <h1 className="text-2xl font-bold">Portfolios</h1>
          {user?.role === 'photographer' && (
            <Link to="/portfolio/upload" className="bg-primary-600 text-white px-4 py-2 rounded text-sm hover:bg-primary-700">
              Create Portfolio
            </Link>
          )}
        </div>
        {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm">{error}</div>}
        {portfolios.length === 0 && !error ? (
