    22	export async function saveFile(input: SaveFileInput): Promise<{
    23	  storagePath: string;
    24	  checksum: string;
    25	  sizeBytes: number;
    26	}> {
    27	  const ext = path.extname(input.originalName) || '';
    28	  const filename = `${uuidv4()}${ext}`;
    29	  const uploadDir = path.resolve(config.uploadDir);
    30	
    31	  // Ensure upload directory exists
    32	  if (!fs.existsSync(uploadDir)) {
    33	    fs.mkdirSync(uploadDir, { recursive: true });
    34	  }
    35	
    36	  const storagePath = path.join(uploadDir, filename);
    37	
    38	  // Prevent path traversal: verify resolved path stays inside upload directory
    39	  const resolvedStorage = path.resolve(storagePath);
    40	  if (!resolvedStorage.startsWith(uploadDir + path.sep) && resolvedStorage !== uploadDir) {
    41	    throw new ValidationError('Invalid storage path');
    42	  }
    43	
    44	  const checksum = computeSHA256(input.buffer);
    45	
    46	  fs.writeFileSync(resolvedStorage, input.buffer);
    47	
    48	  return {
    49	    storagePath: resolvedStorage,
    50	    checksum,
    51	    sizeBytes: input.buffer.length,
    52	  };
    53	}
