=== DELIVERABLE SERVICE: photographer check ===
  // Only the assigned photographer (or admin) can upload deliverables
  const uploader = await User.findById(uploaderId);
  if (uploader?.role !== 'admin') {
    if (!job.photographerId || job.photographerId.toString() !== uploaderId) {
      throw new ForbiddenError('Only the assigned photographer can upload deliverables');
    }
  }

=== CONSENT CONTROLLER: Zod + DATA_CATEGORIES enum ===
export const recordConsentSchema = z.object({
  policyVersion: z.string().min(1),
  accepted: z.boolean().optional(),
});

export const dataCategoryConsentSchema = z.object({
  category: z.enum(DATA_CATEGORIES as unknown as [string, ...string[]]),
  granted: z.boolean().optional().default(true),
});

export const deleteCategoryParamSchema = z.object({
  category: z.enum(DATA_CATEGORIES as unknown as [string, ...string[]]),
});

=== PROFILE SERVICE: first-use consent checks ===
  // Enforce first-use consent for contact/employer data before storing
  const { checkConsent } = await import('./dataCategoryConsent.service');
  if (data.phone || (data as any).contactInfo) {
    const { hasConsent } = await checkConsent(userId, 'contact_information');
    if (!hasConsent) {
      throw new ForbiddenError('Consent for contact_information is required before saving contact data');
    }
  }
  if ((data as any).employer) {
    const { hasConsent } = await checkConsent(userId, 'employer_information');
    if (!hasConsent) {
      throw new ForbiddenError('Consent for employer_information is required before saving employer data');
    }
  }

