    88	export async function editWorkEntry(
    89	  entryId: string,
    90	  userId: string,
    91	  updates: Partial<CreateWorkEntryInput>
    92	) {
    93	  const entry = await WorkEntry.findById(entryId);
    94	  if (!entry) {
    95	    throw new NotFoundError('Work entry not found');
    96	  }
    97	
    98	  if (entry.isLocked) {
    99	    throw new ValidationError('Cannot edit a locked work entry');
   100	  }
   101	
   102	  if (entry.photographerId.toString() !== userId) {
   103	    throw new ForbiddenError('Only the photographer can edit their work entries');
   104	  }
   105	
   106	  // If duration is being updated, validate alignment
   107	  if (updates.durationMinutes !== undefined) {
   108	    if (updates.durationMinutes % TIMESHEET_INCREMENT_MINUTES !== 0) {
   109	      throw new ValidationError(
   110	        `Duration must be in ${TIMESHEET_INCREMENT_MINUTES}-minute increments`
   111	      );
   112	    }
   113	  }
   114	
   115	  // Recalculate subtotal if relevant fields changed
   116	  const job = await Job.findById(entry.jobId);
   117	  if (!job) {
   118	    throw new NotFoundError('Associated job not found');
   119	  }
   120	
   121	  const entryType = updates.entryType || entry.entryType;
   122	  let subtotalCents = entry.subtotalCents;
   123	
   124	  if (entryType === WorkEntryType.TIME) {
   125	    const duration = updates.durationMinutes ?? entry.durationMinutes;
   126	    if (duration) {
   127	      subtotalCents = calculateTimeEntryCents(job.agreedRateCents, duration);
   128	    }
   129	  } else {
   130	    const quantity = updates.quantity ?? entry.quantity;
   131	    const unitRate = updates.unitRateCents ?? entry.unitRateCents ?? job.agreedRateCents;
   132	    if (quantity) {
   133	      subtotalCents = calculatePieceRateCents(unitRate, quantity);
   134	    }
   135	  }
   136	
   137	  // Apply updates and reset confirmations
   138	  Object.assign(entry, updates, {
   139	    subtotalCents,
   140	    clientConfirmedAt: undefined,
   141	    photographerConfirmedAt: undefined,
   142	    lockAt: undefined,
   143	  });
   144	
   145	  // Use $unset for clearing confirmation dates
   146	  await WorkEntry.findByIdAndUpdate(entryId, {
   147	    $set: {
