   149	      subtotalCents,
   150	    },
   151	    $unset: {
   152	      clientConfirmedAt: 1,
   153	      photographerConfirmedAt: 1,
   154	      lockAt: 1,
   155	    },
   156	  });
   157	
   158	  return WorkEntry.findById(entryId);
   159	}
