   161	/**
   162	 * Confirm a work entry (bilateral confirmation).
   163	 * Client or photographer can confirm.
   164	 * Once both confirm, set lockAt = now + 48h.
   165	 */
   166	export async function confirmWorkEntry(entryId: string, userId: string) {
   167	  const entry = await WorkEntry.findById(entryId);
   168	  if (!entry) {
   169	    throw new NotFoundError('Work entry not found');
   170	  }
   171	
   172	  if (entry.isLocked) {
   173	    throw new ValidationError('Work entry is already locked');
   174	  }
   175	
   176	  const job = await Job.findById(entry.jobId);
   177	  if (!job) {
   178	    throw new NotFoundError('Associated job not found');
   179	  }
   180	
   181	  const isClient = job.clientId.toString() === userId;
   182	  const isPhotographer = entry.photographerId.toString() === userId;
   183	
   184	  if (!isClient && !isPhotographer) {
   185	    throw new ForbiddenError('Only the client or photographer can confirm work entries');
   186	  }
   187	
   188	  if (isClient) {
   189	    if (entry.clientConfirmedAt) {
   190	      throw new ValidationError('Client has already confirmed this entry');
   191	    }
   192	    entry.clientConfirmedAt = new Date();
   193	  }
   194	
   195	  if (isPhotographer) {
   196	    if (entry.photographerConfirmedAt) {
   197	      throw new ValidationError('Photographer has already confirmed this entry');
   198	    }
   199	    entry.photographerConfirmedAt = new Date();
   200	  }
   201	
   202	  // If both confirmed, schedule lock
   203	  if (entry.clientConfirmedAt && entry.photographerConfirmedAt) {
   204	    const lockAt = new Date();
   205	    lockAt.setHours(lockAt.getHours() + LOCK_HOURS);
   206	    entry.lockAt = lockAt;
   207	  }
   208	
   209	  await entry.save();
   210	  return entry;
   211	}
