     1	import { useEffect, useState } from 'react';
     2	import { adminApi } from '../../api/admin.api';
     3	import { formatDateTime } from '../../utils/formatters';
     4	import LoadingSpinner from '../../components/shared/LoadingSpinner';
     5	import StatusBadge from '../../components/shared/StatusBadge';
     6	
     7	export default function VerificationReviewPage() {
     8	  const [requests, setRequests] = useState<any[]>([]);
     9	  const [loading, setLoading] = useState(true);
    10	  const [error, setError] = useState('');
    11	  const [statusFilter, setStatusFilter] = useState('pending');
    12	  const [actionLoading, setActionLoading] = useState('');
    13	  const [rejectionReason, setRejectionReason] = useState('');
    14	  const [rejectingId, setRejectingId] = useState('');
    15	
    16	  const fetchData = () => {
    17	    setLoading(true);
    18	    const params: any = {};
    19	    if (statusFilter) params.status = statusFilter;
    20	    adminApi.getVerificationRequests(params)
    21	      .then(res => setRequests(res.data.items || res.data || []))
    22	      .catch(err => setError(err.response?.data?.msg || 'Failed to load verification requests'))
    23	      .finally(() => setLoading(false));
    24	  };
    25	
    26	  useEffect(() => { fetchData(); }, [statusFilter]);
    27	
    28	  const handleApprove = async (id: string) => {
    29	    setActionLoading(id);
    30	    try {
    31	      await adminApi.reviewVerification(id, { decision: 'approved' });
    32	      fetchData();
    33	    } catch (err: any) {
    34	      setError(err.response?.data?.msg || 'Failed to approve');
    35	    } finally {
    36	      setActionLoading('');
    37	    }
    38	  };
    39	
    40	  const handleReject = async (id: string) => {
    41	    if (!rejectionReason.trim()) { setError('Please provide a rejection reason.'); return; }
    42	    setActionLoading(id);
    43	    try {
    44	      await adminApi.reviewVerification(id, { decision: 'rejected', rejectionReason });
    45	      setRejectingId('');
    46	      setRejectionReason('');
    47	      fetchData();
    48	    } catch (err: any) {
    49	      setError(err.response?.data?.msg || 'Failed to reject');
    50	    } finally {
    51	      setActionLoading('');
    52	    }
    53	  };
    54	
    55	  return (
    56	    <div>
    57	      <h1 className="text-2xl font-bold mb-6">Verification Review</h1>
    58	      {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm">{error}</div>}
    59	
    60	      <div className="mb-6">
    61	        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="border rounded px-3 py-2 text-sm">
    62	          <option value="">All</option>
    63	          <option value="pending">Pending</option>
    64	          <option value="approved">Approved</option>
    65	          <option value="rejected">Rejected</option>
    66	        </select>
    67	      </div>
    68	
    69	      {loading ? (
    70	        <LoadingSpinner message="Loading requests..." />
    71	      ) : requests.length === 0 ? (
    72	        <div className="bg-white rounded-lg shadow p-8 text-center text-gray-500">No verification requests found.</div>
    73	      ) : (
    74	        <div className="space-y-4">
    75	          {requests.map(req => (
    76	            <div key={req._id} className="bg-white rounded-lg shadow p-6">
    77	              <div className="flex items-start justify-between">
    78	                <div>
    79	                  <div className="flex items-center gap-2 mb-2">
    80	                    <span className="font-semibold text-sm">User: <span className="font-mono text-xs">{req.userId || req.username}</span></span>
    81	                    <StatusBadge status={req.status} />
    82	                  </div>
    83	                  <p className="text-sm text-gray-600">Document Type: <span className="capitalize">{req.documentType?.replace(/_/g, ' ') || 'N/A'}</span></p>
    84	                  {req.notes && <p className="text-sm text-gray-500 mt-1">Notes: {req.notes}</p>}
    85	                  <p className="text-xs text-gray-400 mt-2">Submitted: {formatDateTime(req.submittedAt || req.createdAt)}</p>
    86	                  {req.documents && (
    87	                    <div className="mt-2 flex gap-2">
    88	                      {(Array.isArray(req.documents) ? req.documents : []).map((doc: any, i: number) => (
    89	                        <a key={i} href={doc.url || doc} target="_blank" rel="noopener noreferrer" className="text-primary-600 hover:underline text-xs">
    90	                          Document {i + 1}
    91	                        </a>
    92	                      ))}
    93	                    </div>
    94	                  )}
    95	                </div>
    96	                {req.status === 'pending' && (
    97	                  <div className="flex gap-2">
    98	                    <button
    99	                      onClick={() => handleApprove(req._id)}
   100	                      disabled={actionLoading === req._id}
   101	                      className="bg-green-600 text-white px-3 py-1.5 rounded text-xs hover:bg-green-700 disabled:opacity-50"
   102	                    >
   103	                      Approve
   104	                    </button>
   105	                    <button
   106	                      onClick={() => setRejectingId(rejectingId === req._id ? '' : req._id)}
   107	                      disabled={actionLoading === req._id}
   108	                      className="bg-red-600 text-white px-3 py-1.5 rounded text-xs hover:bg-red-700 disabled:opacity-50"
   109	                    >
   110	                      Reject
   111	                    </button>
   112	                  </div>
   113	                )}
   114	              </div>
   115	              {rejectingId === req._id && (
   116	                <div className="mt-4 flex gap-2">
   117	                  <input
   118	                    type="text"
   119	                    placeholder="Rejection reason..."
   120	                    value={rejectionReason}
   121	                    onChange={e => setRejectionReason(e.target.value)}
   122	                    className="flex-1 border rounded px-3 py-2 text-sm"
