import { render, screen } from '@testing-library/react';
import { MemoryRouter } from 'react-router-dom';
import { AuthProvider } from '../context/AuthContext';
import App from '../App';

function renderAuthenticated(route: string, role = 'alumni') {
  localStorage.setItem('token', 'fake-token');
  localStorage.setItem('user', JSON.stringify({
    _id: '1', username: 'testuser', role, email: 'test@t.com',
    accountStatus: 'active', isAlumni: true, communityId: 'c1',
  }));
  return render(
    <MemoryRouter initialEntries={[route]}>
      <AuthProvider>
        <App />
      </AuthProvider>
    </MemoryRouter>,
  );
}

describe('Settlement export routing & access', () => {
  beforeEach(() => { localStorage.clear(); });

  it('renders settlement detail at /settlements/:id for authenticated user', () => {
    renderAuthenticated('/settlements/abc123');
    expect(screen.queryByRole('button', { name: /sign in|log in/i })).not.toBeInTheDocument();
  });

  it('redirects unauthenticated user to login', () => {
    render(
      <MemoryRouter initialEntries={['/settlements/abc123']}>
        <AuthProvider>
          <App />
        </AuthProvider>
      </MemoryRouter>,
    );
    expect(screen.getByRole('button', { name: /sign in|log in/i })).toBeInTheDocument();
  });
});

describe('Settlement export 403 handling (unit)', () => {
  it('handleExport catches 403 and sets error state', async () => {
    // Simulate what the handleExport function does on 403
    const setError = vi.fn();
    const mockExportApi = vi.fn().mockRejectedValue({
      response: { status: 403, data: { msg: 'Access denied' } },
    });

    try {
      await mockExportApi();
    } catch (err: any) {
      const msg = err.response?.data?.msg || 'Failed to export';
      setError(msg);
    }

    expect(setError).toHaveBeenCalledWith('Access denied');
    expect(mockExportApi).toHaveBeenCalled();
  });

  it('handleExport shows generic error on network failure', async () => {
    const setError = vi.fn();
    const mockExportApi = vi.fn().mockRejectedValue(new Error('Network Error'));

    try {
      await mockExportApi();
    } catch (err: any) {
      const msg = err.response?.data?.msg || 'Failed to export pdf';
      setError(msg);
    }

    expect(setError).toHaveBeenCalledWith('Failed to export pdf');
  });

  it('successful export does not set error', async () => {
    const setError = vi.fn();
    const mockExportApi = vi.fn().mockResolvedValue({ data: new Blob(['pdf content']) });

    try {
      const res = await mockExportApi();
      // Would create blob URL and trigger download
      expect(res.data).toBeInstanceOf(Blob);
    } catch (err: any) {
      setError(err.response?.data?.msg || 'Failed to export');
    }

    expect(setError).not.toHaveBeenCalled();
  });
});
"}

